INSERT INTO `categories` (`id`, `name`, `slug`, `description`, `image_url`, `created_at`) VALUES
(1, 'Cửa nhôm kính', 'cua-nhom-kinh', 'Các loại cửa nhôm kính cao cấp, cửa lùa, cửa mở quay, cửa sổ mở hất với khung nhôm Xingfa, Topal chính hãng. Bền đẹp, cách âm cách nhiệt tốt.', 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Nhom+Kinh', '2026-05-30 15:04:51'),
(2, 'Vách kính', 'vach-kinh', 'Vách kính cường lực trang trí, vách ngăn phòng, vách kính mặt dựng cho văn phòng và nhà ở. Thiết kế hiện đại, tối ưu không gian.', 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Kinh', '2026-05-30 15:04:51'),
(3, 'Lan can kính', 'lan-can-kinh', 'Lan can kính cường lực cho ban công, cầu thang, sân thượng. An toàn tuyệt đối, tầm nhìn thoáng đãng, nâng tầm thẩm mỹ công trình.', 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Lan+Can+Kinh', '2026-05-30 15:04:51'),
(4, 'Mái kính', 'mai-kinh', 'Mái kính cường lực sân thượng, giếng trời, mái hiên. Lấy sáng tự nhiên, chống mưa gió, tạo không gian sống xanh.', 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Mai+Kinh', '2026-05-30 15:04:51'),
(5, 'Cửa cuốn', 'cua-cuon', 'Cửa cuốn nhôm, cửa cuốn tấm liền, cửa cuốn Đức cao cấp. Tiện lợi, bảo mật, vận hành êm ái bằng motor tự động.', 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Cuon', '2026-05-30 15:04:51'),
(6, 'Phòng tắm kính', 'phong-tam-kinh', 'Vách tắm kính, cabin tắm kính cường lực thiết kế sang trọng. Chống nước tuyệt đối, dễ vệ sinh, phù hợp mọi không gian phòng tắm.', 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Phong+Tam+Kinh', '2026-05-30 15:04:51');
INSERT INTO `products` (`id`, `name`, `slug`, `description`, `price_range`, `category_id`, `image_url`, `thumbnail_url`, `is_featured`, `created_at`, `code`, `brand`, `color`, `material`, `option_name`, `thickness`, `hardware`, `warranty`, `soundproof`, `status`, `gallery_images`, `features`, `guides`) VALUES
(1, 'Cửa lùa nhôm Xingfa 4 cánh', 'cua-lua-nhom-xingfa-4-canh', 'Cửa lùa nhôm Xingfa 4 cánh cao cấp, sử dụng thanh nhôm Xingfa chính hãng nhập khẩu Quảng Đông. Kính cường lực 8mm an toàn, hệ ray trượt êm ái, phù hợp cho phòng khách, ban công rộng. Bảo hành khung nhôm 10 năm.', '3.500.000 - 6.000.000 VNĐ/m²', 1, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780128787/thanh-thinh-phat/ftzltg3jz7nmm8ggcduu.jpg', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780128787/thanh-thinh-phat/ftzltg3jz7nmm8ggcduu.jpg', 1, '2026-05-30 15:04:51', 'CNK-XF-001', 'Xingfa Quảng Đông', 'Ghi xám, Nâu cafe, Trắng sứ, Đen', 'Nhôm Xingfa & Kính cường lực 8-12mm', 'TIÊU CHUẨN', 'Nhôm hệ 55, dày 1.4mm - 2.0mm', 'Kinlong chính hãng nhập khẩu', '5 năm nhôm, 2 năm phụ kiện', 'Cách âm vượt trội, cản gió bão', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780128787/thanh-thinh-phat/ftzltg3jz7nmm8ggcduu.jpg\",\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780130951/thanh-thinh-phat/jnx8tdobgmwutfw2axjh.png\",\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780130988/thanh-thinh-phat/kplxbeokpvj03fimrdwc.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(2, 'Cửa đi nhôm kính cường lực', 'cua-di-nhom-kinh-cuong-luc', 'Cửa đi mở quay 1 cánh hoặc 2 cánh bằng nhôm kính cường lực. Khung nhôm dày dặn, bản lề chịu lực cao, kính cường lực 10mm chống va đập. Thích hợp cho cửa chính, cửa phòng ngủ, cửa ban công.', '2.800.000 - 4.500.000 VNĐ/m²', 1, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134623/thanh-thinh-phat/m6avxai70tyux7ximwuv.jpg', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134623/thanh-thinh-phat/m6avxai70tyux7ximwuv.jpg', 0, '2026-05-30 15:04:51', 'CNK-XF-002', 'Xingfa Quảng Đông', 'Ghi xám, Nâu cafe, Trắng sứ, Đen', 'Nhôm Xingfa & Kính cường lực 8-12mm', 'TIÊU CHUẨN', 'Nhôm hệ 55, dày 1.4mm - 2.0mm', 'Kinlong chính hãng nhập khẩu', '5 năm nhôm, 2 năm phụ kiện', 'Cách âm vượt trội, cản gió bão', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134623/thanh-thinh-phat/m6avxai70tyux7ximwuv.jpg\",\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134620/thanh-thinh-phat/smrmptnngpuoz66vbf2k.jpg\",\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134624/thanh-thinh-phat/kkotfbn6pojmluczxzfu.jpg\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(3, 'Cửa sổ mở hất nhôm Xingfa', 'cua-so-mo-hat-nhom-xingfa', 'Cửa sổ mở hất nhôm Xingfa hệ 55, mở góc 45 độ giúp đón gió tự nhiên mà vẫn chắn được mưa tạt. Kính hộp 2 lớp cách âm cách nhiệt hiệu quả. Phù hợp cho phòng ngủ, phòng làm việc.', '2.200.000 - 3.800.000 VNĐ/m²', 1, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134684/thanh-thinh-phat/uxbcimw4uysr1ozqcynn.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134684/thanh-thinh-phat/uxbcimw4uysr1ozqcynn.png', 0, '2026-05-30 15:04:51', 'CNK-XF-003', 'Xingfa Quảng Đông', 'Ghi xám, Nâu cafe, Trắng sứ, Đen', 'Nhôm Xingfa & Kính cường lực 8-12mm', 'TIÊU CHUẨN', 'Nhôm hệ 55, dày 1.4mm - 2.0mm', 'Kinlong chính hãng nhập khẩu', '5 năm nhôm, 2 năm phụ kiện', 'Cách âm vượt trội, cản gió bão', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134684/thanh-thinh-phat/uxbcimw4uysr1ozqcynn.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(4, 'Vách kính cường lực 10mm', 'vach-kinh-cuong-luc-10mm', 'Vách kính cường lực 10mm trong suốt, chịu lực va đập gấp 5 lần kính thường. Phù hợp làm vách ngăn văn phòng, showroom, cửa hàng. Liên kết bằng phụ kiện inox 304 sáng bóng, bền bỉ theo thời gian.', '1.200.000 - 2.000.000 VNĐ/m²', 2, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780131600/thanh-thinh-phat/q7zo67fl8xxplaq980ox.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780131600/thanh-thinh-phat/q7zo67fl8xxplaq980ox.png', 1, '2026-05-30 15:04:51', 'VK-CL-004', 'Hải Long / Việt Nhật', 'Trong suốt, mờ cát, phản quang', 'Kính cường lực Temper 10mm - 12mm', 'CAO CẤP', 'Kính temper dày 10mm - 12mm', 'Nẹp sập nhôm định hình / Đế sập inox', '2 năm', 'Phân chia không gian tốt, cách âm tốt', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780131600/thanh-thinh-phat/q7zo67fl8xxplaq980ox.png\",\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780131628/thanh-thinh-phat/tai1cdyd3lyflbml0okx.png\",\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780131673/thanh-thinh-phat/n9yachnkbof5zpujewuy.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(5, 'Vách ngăn phòng kính cường lực', 'vach-ngan-phong-kinh-cuong-luc', 'Vách ngăn phòng bằng kính cường lực kết hợp khung nhôm, tạo không gian riêng tư mà vẫn giữ được sự thoáng đãng. Có thể lắp thêm rèm cuốn hoặc film mờ tùy nhu cầu. Thi công nhanh, không ảnh hưởng kết cấu.', '1.500.000 - 2.500.000 VNĐ/m²', 2, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134789/thanh-thinh-phat/undgrodb30fgtmi4nayq.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134789/thanh-thinh-phat/undgrodb30fgtmi4nayq.png', 0, '2026-05-30 15:04:51', 'VK-CL-005', 'Hải Long / Việt Nhật', 'Trong suốt, mờ cát, phản quang', 'Kính cường lực Temper 10mm - 12mm', 'CAO CẤP', 'Kính temper dày 10mm - 12mm', 'Nẹp sập nhôm định hình / Đế sập inox', '2 năm', 'Phân chia không gian tốt, cách âm tốt', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134789/thanh-thinh-phat/undgrodb30fgtmi4nayq.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(6, 'Vách kính mặt dựng', 'vach-kinh-mat-dung', 'Hệ vách kính mặt dựng (curtain wall) dành cho tòa nhà văn phòng, trung tâm thương mại. Sử dụng kính hộp Low-E cách nhiệt, khung nhôm hệ lớn chịu gió bão. Tôn vẻ hiện đại và chuyên nghiệp cho công trình.', '2.500.000 - 4.000.000 VNĐ/m²', 2, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Kinh+Mat+Dung', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Vach+Kinh+Mat+Dung', 0, '2026-05-30 15:04:51', 'VK-CL-006', 'Hải Long / Việt Nhật', 'Trong suốt, mờ cát, phản quang', 'Kính cường lực Temper 10mm - 12mm', 'CAO CẤP', 'Kính temper dày 10mm - 12mm', 'Nẹp sập nhôm định hình / Đế sập inox', '2 năm', 'Phân chia không gian tốt, cách âm tốt', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Kinh+Mat+Dung\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Vach+Kinh+Mat+Dung\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Kinh+Detail+1\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(7, 'Lan can kính cường lực ban công', 'lan-can-kinh-cuong-luc-ban-cong', 'Lan can kính cường lực 12mm cho ban công chung cư, nhà phố. Kẹp kính bằng inox 304 hoặc nhôm đúc chắc chắn. Tầm nhìn panorama thoáng đãng, không che chắn view, đạt tiêu chuẩn an toàn xây dựng.', '1.800.000 - 3.200.000 VNĐ/m²', 3, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Lan+Can+Ban+Cong', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Lan+Can+Ban+Cong', 1, '2026-05-30 15:04:51', 'LC-KK-007', 'Thành Thịnh Phát', 'Kính trong suốt, phụ kiện inox sáng bóng', 'Kính cường lực 12mm & Trụ Inox 304', 'TIÊU CHUẨN', 'Kính cường lực dày 12mm', 'Trụ lửng Inox 304, tay vịn gỗ căm xe', '3 năm', 'Chịu lực cao, an toàn tuyệt đối', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Lan+Can+Ban+Cong\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Lan+Can+Ban+Cong\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Thi+Cong+Thuc+Te\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(8, 'Lan can cầu thang kính', 'lan-can-cau-thang-kinh', 'Lan can cầu thang kính cường lực tạo cảm giác rộng rãi cho không gian. Kính dày 10-12mm kết hợp tay vịn inox hoặc gỗ tự nhiên. Phù hợp cho biệt thự, nhà phố hiện đại, khách sạn, resort.', '1.500.000 - 2.800.000 VNĐ/m²', 3, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Lan+Can+Cau+Thang', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Lan+Can+Cau+Thang', 0, '2026-05-30 15:04:51', 'LC-KK-008', 'Thành Thịnh Phát', 'Kính trong suốt, phụ kiện inox sáng bóng', 'Kính cường lực 12mm & Trụ Inox 304', 'TIÊU CHUẨN', 'Kính cường lực dày 12mm', 'Trụ lửng Inox 304, tay vịn gỗ căm xe', '3 năm', 'Chịu lực cao, an toàn tuyệt đối', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Lan+Can+Cau+Thang\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Lan+Can+Cau+Thang\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Thi+Cong+Thuc+Te\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(9, 'Lan can kính trụ inox', 'lan-can-kinh-tru-inox', 'Lan can kính cường lực với trụ inox 304 tròn hoặc vuông, thiết kế thanh mảnh tinh tế. Dễ dàng lắp đặt trên nhiều loại địa hình, phù hợp cho sân thượng, hành lang, ban công nhà ở và công trình công cộng.', '1.200.000 - 2.200.000 VNĐ/m²', 3, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Lan+Can+Tru+Inox', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Lan+Can+Tru+Inox', 0, '2026-05-30 15:04:51', 'LC-KK-009', 'Thành Thịnh Phát', 'Kính trong suốt, phụ kiện inox sáng bóng', 'Kính cường lực 12mm & Trụ Inox 304', 'TIÊU CHUẨN', 'Kính cường lực dày 12mm', 'Trụ lửng Inox 304, tay vịn gỗ căm xe', '3 năm', 'Chịu lực cao, an toàn tuyệt đối', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Lan+Can+Tru+Inox\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Lan+Can+Tru+Inox\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Thi+Cong+Thuc+Te\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(10, 'Mái kính cường lực sân thượng', 'mai-kinh-cuong-luc-san-thuong', 'Mái kính cường lực dán an toàn (laminated) cho sân thượng, tạo không gian thư giãn tuyệt vời. Khung thép sơn tĩnh điện hoặc khung nhôm chịu lực, chống rỉ sét. Kính có thể chọn trong suốt hoặc phản quang chống nóng.', '2.000.000 - 3.500.000 VNĐ/m²', 4, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Mai+Kinh+San+Thuong', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Mai+Kinh+San+Thuong', 1, '2026-05-30 15:04:51', 'MK-CL-010', 'Thành Thịnh Phát', 'Kính trong, kính phản quang chống nhiệt', 'Kính cường lực dán 11.52mm & Khung thép mạ kẽm', 'TIÊU CHUẨN', 'Kính dán an toàn cường lực 11.52mm', 'Chốt spider inox 304, keo kết cấu chống thấm', '5 năm hệ khung, 2 năm kính', 'Lấy sáng tự nhiên, chống mưa nắng và tia cực tím', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Mai+Kinh+San+Thuong\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Mai+Kinh+San+Thuong\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Thi+Cong+Thuc+Te\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(11, 'Giếng trời kính cường lực', 'gieng-troi-kinh-cuong-luc', 'Giếng trời (skylight) kính cường lực dán an toàn, đưa ánh sáng tự nhiên vào không gian sống. Hệ khung nhôm kín nước, gioăng cao su EPDM chống thấm tuyệt đối. Giải pháp hoàn hảo cho nhà phố hẹp, tầng hầm.', '2.500.000 - 4.500.000 VNĐ/m²', 4, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Gieng+Troi+Kinh', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Gieng+Troi+Kinh', 0, '2026-05-30 15:04:51', 'MK-CL-011', 'Thành Thịnh Phát', 'Kính trong, kính phản quang chống nhiệt', 'Kính cường lực dán 11.52mm & Khung thép mạ kẽm', 'TIÊU CHUẨN', 'Kính dán an toàn cường lực 11.52mm', 'Chốt spider inox 304, keo kết cấu chống thấm', '5 năm hệ khung, 2 năm kính', 'Lấy sáng tự nhiên, chống mưa nắng và tia cực tím', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Gieng+Troi+Kinh\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Gieng+Troi+Kinh\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Thi+Cong+Thuc+Te\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(12, 'Mái hiên kính cường lực', 'mai-hien-kinh-cuong-luc', 'Mái hiên kính cường lực che mưa nắng cho lối vào, sân trước, ban công. Thiết kế tối giản với bát spider inox, kính cường lực 12mm trong suốt. Tôn vẻ sang trọng, hiện đại cho mặt tiền ngôi nhà.', '1.800.000 - 3.000.000 VNĐ/m²', 4, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Mai+Hien+Kinh', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Mai+Hien+Kinh', 0, '2026-05-30 15:04:51', 'MK-CL-012', 'Thành Thịnh Phát', 'Kính trong, kính phản quang chống nhiệt', 'Kính cường lực dán 11.52mm & Khung thép mạ kẽm', 'TIÊU CHUẨN', 'Kính dán an toàn cường lực 11.52mm', 'Chốt spider inox 304, keo kết cấu chống thấm', '5 năm hệ khung, 2 năm kính', 'Lấy sáng tự nhiên, chống mưa nắng và tia cực tím', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Mai+Hien+Kinh\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Mai+Hien+Kinh\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Thi+Cong+Thuc+Te\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(13, 'Cửa cuốn nhôm khe thoáng', 'cua-cuon-nhom-khe-thoang', 'Cửa cuốn nhôm khe thoáng cao cấp, nan nhôm dày 0.7-1.0mm, có khe thoáng gió khi đóng cửa. Motor Đài Loan êm ái, điều khiển remote từ xa tiện lợi. Phù hợp cho nhà phố, cửa hàng, garage ô tô.', '1.500.000 - 2.800.000 VNĐ/m²', 5, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135448/thanh-thinh-phat/fjsnxhw64bpvyltdevk4.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135448/thanh-thinh-phat/fjsnxhw64bpvyltdevk4.png', 1, '2026-05-30 15:04:51', 'CC-AD-013', 'Austdoor chính hãng', 'Ghi sáng (#5), Nâu cafe (#7)', 'Hợp kim nhôm AL 6063 T5', 'TIÊU CHUẨN', 'Độ dày nan cửa 0.9mm - 1.2mm', 'Motor Austdoor nhập khẩu đồng bộ', '5 năm cho motor, 2 năm cho nan cửa', 'Vận hành êm ái, chống cạy phá', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135448/thanh-thinh-phat/fjsnxhw64bpvyltdevk4.png\",\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135475/thanh-thinh-phat/n5bpue19kps57o67uzyt.png\",\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135484/thanh-thinh-phat/djp1ia73wsjlozlaptdh.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(14, 'Cửa cuốn tấm liền', 'cua-cuon-tam-lien', 'Cửa cuốn tấm liền (solid) bằng thép mạ kẽm hoặc nhôm, bề mặt phẳng kín. Cách âm, cách nhiệt, chống trộm hiệu quả. Sơn tĩnh điện nhiều màu sắc, motor tự động với hệ thống dừng khẩn cấp an toàn.', '1.200.000 - 2.200.000 VNĐ/m²', 5, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Cuon+Tam+Lien', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Cua+Cuon+Tam+Lien', 0, '2026-05-30 15:04:51', 'CC-AD-014', 'Austdoor chính hãng', 'Ghi sáng (#5), Nâu cafe (#7)', 'Hợp kim nhôm AL 6063 T5', 'TIÊU CHUẨN', 'Độ dày nan cửa 0.9mm - 1.2mm', 'Motor Austdoor nhập khẩu đồng bộ', '5 năm cho motor, 2 năm cho nan cửa', 'Vận hành êm ái, chống cạy phá', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Cuon+Tam+Lien\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Cua+Cuon+Tam+Lien\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Thi+Cong+Thuc+Te\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(15, 'Cửa cuốn Đức Austdoor', 'cua-cuon-duc-austdoor', 'Cửa cuốn Austdoor thương hiệu Đức sản xuất tại Việt Nam. Nan nhôm 2 lớp cách âm cách nhiệt, motor Hitachi bền bỉ, hệ thống khóa từ chống cạy. Bảo hành motor 5 năm, nan nhôm 10 năm. Đẳng cấp và an tâm.', '2.500.000 - 4.000.000 VNĐ/m²', 5, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Cuon+Austdoor', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Cua+Cuon+Austdoor', 0, '2026-05-30 15:04:51', 'CC-AD-015', 'Austdoor chính hãng', 'Ghi sáng (#5), Nâu cafe (#7)', 'Hợp kim nhôm AL 6063 T5', 'TIÊU CHUẨN', 'Độ dày nan cửa 0.9mm - 1.2mm', 'Motor Austdoor nhập khẩu đồng bộ', '5 năm cho motor, 2 năm cho nan cửa', 'Vận hành êm ái, chống cạy phá', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Cuon+Austdoor\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Cua+Cuon+Austdoor\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Thi+Cong+Thuc+Te\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(16, 'Vách tắm kính 90 độ', 'vach-tam-kinh-90-do', 'Vách tắm kính cường lực 10mm góc 90 độ, thiết kế tối giản sang trọng. Phụ kiện bản lề, kẹp kính inox 304 cao cấp, gioăng silicone chống nước. Phù hợp phòng tắm diện tích nhỏ đến trung bình.', '2.500.000 - 4.000.000 VNĐ/bộ', 6, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Tam+90+Do', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Vach+Tam+90+Do', 1, '2026-05-30 15:04:51', 'PT-PT-016', 'VVP Thái Lan / Hafele', 'Trong suốt', 'Kính cường lực 10mm & Inox 304', 'TIÊU CHUẨN', 'Kính cường lực dày 10mm', 'Bản lề cabin tắm, định vị kính, giằng inox, gioăng từ', '2 năm hoàn thiện', 'Ngăn nước tuyệt đối, giữ ấm cực tốt', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Tam+90+Do\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Vach+Tam+90+Do\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Thi+Cong+Thuc+Te\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(17, 'Cabin tắm kính cường lực', 'cabin-tam-kinh-cuong-luc', 'Cabin tắm kính cường lực đúc khuôn, gồm khay tắm, vách kính và phụ kiện hoàn chỉnh. Kính cường lực 8-10mm, khung nhôm mạ chrome sáng bóng. Lắp đặt nhanh gọn, đa dạng kích thước 80x80, 90x90, 100x100 cm.', '4.500.000 - 8.000.000 VNĐ/bộ', 6, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cabin+Tam+Kinh', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Cabin+Tam+Kinh', 0, '2026-05-30 15:04:51', 'PT-PT-017', 'VVP Thái Lan / Hafele', 'Trong suốt', 'Kính cường lực 10mm & Inox 304', 'TIÊU CHUẨN', 'Kính cường lực dày 10mm', 'Bản lề cabin tắm, định vị kính, giằng inox, gioăng từ', '2 năm hoàn thiện', 'Ngăn nước tuyệt đối, giữ ấm cực tốt', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cabin+Tam+Kinh\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Cabin+Tam+Kinh\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Thi+Cong+Thuc+Te\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(18, 'Vách tắm kính cửa lùa', 'vach-tam-kinh-cua-lua', 'Vách tắm kính cường lực cửa lùa trượt êm ái trên ray inox, tiết kiệm không gian mở cửa. Kính dày 8-10mm, bề mặt phủ nano chống bám nước, dễ lau chùi. Phù hợp phòng tắm dài, bồn tắm nằm.', '3.000.000 - 5.500.000 VNĐ/bộ', 6, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Tam+Cua+Lua', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Vach+Tam+Cua+Lua', 0, '2026-05-30 15:04:51', 'PT-PT-018', 'VVP Thái Lan / Hafele', 'Trong suốt', 'Kính cường lực 10mm & Inox 304', 'TIÊU CHUẨN', 'Kính cường lực dày 10mm', 'Bản lề cabin tắm, định vị kính, giằng inox, gioăng từ', '2 năm hoàn thiện', 'Ngăn nước tuyệt đối, giữ ấm cực tốt', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Tam+Cua+Lua\",\"https://placehold.co/400x300/1B2A4A/FFFFFF?text=Vach+Tam+Cua+Lua\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Thi+Cong+Thuc+Te\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(19, 'Cửa đi mở quay nhôm Xingfa hệ 55', 'cua-di-mo-quay-nhom-xingfa-he-55', 'Cửa đi mở quay nhôm Xingfa hệ 55 chính hãng Quảng Đông dày 2.0mm. Kính cường lực an toàn, thiết kế sang trọng, độ bền vượt trội thích hợp làm cửa chính hoặc cửa ra vào ban công.', '2.500.000 - 3.800.000 VNĐ/m²', 1, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135036/thanh-thinh-phat/o1kvaxrm7ojykw9keryc.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135036/thanh-thinh-phat/o1kvaxrm7ojykw9keryc.png', 1, '2026-05-30 16:53:08', 'CNK-XF-004', 'Xingfa Quảng Đông', 'Ghi xám, Nâu cafe, Trắng sứ, Vân gỗ', 'Nhôm Xingfa hệ 55 & Kính cường lực Chu Lai', 'TIÊU CHUẨN', 'Thanh nhôm dày 2.0mm', 'Phụ kiện Kinlong nhập khẩu đồng bộ', '5 năm cho khung nhôm, 2 năm phụ kiện', 'Cách âm cách nhiệt tiêu chuẩn châu Âu', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135036/thanh-thinh-phat/o1kvaxrm7ojykw9keryc.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(20, 'Cửa sổ mở lùa nhôm Xingfa 2 cánh', 'cua-so-mo-lua-nhom-xingfa-2-canh', 'Cửa sổ mở lùa nhôm Xingfa 2 cánh thiết kế nhỏ gọn, trượt nhẹ nhàng êm ái trên ray. Giải pháp tối ưu cho không gian hẹp giúp lấy sáng và thông gió mà không chiếm diện tích mở cửa.', '2.100.000 - 3.200.000 VNĐ/m²', 1, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134845/thanh-thinh-phat/sxebxlxxts2meyrcigna.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134845/thanh-thinh-phat/sxebxlxxts2meyrcigna.png', 0, '2026-05-30 16:53:08', 'CNK-XF-005', 'Xingfa Quảng Đông', 'Đen tuyền, Ghi xám, Trắng sứ', 'Nhôm hệ 93 & Kính dán an toàn 2 lớp', 'TIÊU CHUẨN', 'Khung nhôm dày 2.0mm', 'Phụ kiện Kinlong / Hehexin chính hãng', '5 năm khung nhôm, 2 năm phụ kiện', 'Cách âm tốt, chống nước mưa hắt tuyệt đối', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134845/thanh-thinh-phat/sxebxlxxts2meyrcigna.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(21, 'Cửa đi xếp trượt nhôm Xingfa 6 cánh', 'cua-di-xep-truot-nhom-xingfa-6-canh', 'Cửa đi mở xếp trượt 6 cánh nhôm Xingfa sang trọng, mở rộng tối đa 100% diện tích lối đi. Rất thích hợp làm cửa mặt tiền, biệt thự sân vườn, lối ra hồ bơi hoặc showroom lớn.', '4.000.000 - 5.800.000 VNĐ/m²', 1, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134883/thanh-thinh-phat/etgu0rt9s5t9gdo5yedx.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134883/thanh-thinh-phat/etgu0rt9s5t9gdo5yedx.png', 0, '2026-05-30 16:53:08', 'CNK-XF-006', 'Xingfa Quảng Đông', 'Ghi xám, Nâu ánh kim', 'Nhôm Xingfa hệ 63 & Kính cường lực 10mm', 'CAO CẤP', 'Khung nhôm dày 2.0mm - 2.5mm', 'Phụ kiện Sigico / Hopo cao cấp đồng bộ', '5 năm', 'Thiết kế đa khoang cách âm, cản gió cấp lực cực tốt', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134883/thanh-thinh-phat/etgu0rt9s5t9gdo5yedx.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(22, 'Cửa sổ mở quay nhôm Xingfa cao cấp', 'cua-so-mo-quay-nhom-xingfa-cao-cap', 'Cửa sổ mở quay 1 cánh hoặc 2 cánh nhôm Xingfa hệ 55. Khung bao và cánh định hình vững chắc kết hợp bản lề chữ A chống gió giật, mở tối đa góc 90 độ tiện lợi.', '2.300.000 - 3.500.000 VNĐ/m²', 1, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134944/thanh-thinh-phat/zlff8ukn7qe1r2jqwaf8.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134944/thanh-thinh-phat/zlff8ukn7qe1r2jqwaf8.png', 0, '2026-05-30 16:53:08', 'CNK-XF-007', 'Xingfa Quảng Đông', 'Trắng sứ, Ghi xám, Đen', 'Nhôm Xingfa & Kính Temper Hải Long', 'TIÊU CHUẨN', 'Thanh nhôm dày 1.4mm', 'Bản lề chữ A, thanh định vị chống sập Kinlong', '5 năm', 'Gioăng EPDM kín khít cách âm, chống ồn tốt', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134944/thanh-thinh-phat/zlff8ukn7qe1r2jqwaf8.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(23, 'Vách kính cường lực văn phòng cách âm', 'vach-kinh-cuong-luc-van-phong-cach-am', 'Vách kính văn phòng sử dụng kính cường lực dày 12mm chịu lực và cách âm cực kỳ hiệu quả. Phân tách các phòng ban làm việc chuyên nghiệp mà vẫn giữ trọn không gian mở thông thoáng.', '1.400.000 - 2.200.000 VNĐ/m²', 2, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134986/thanh-thinh-phat/proccxueggqyrp3yoek1.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134986/thanh-thinh-phat/proccxueggqyrp3yoek1.png', 1, '2026-05-30 16:53:08', 'VK-CL-004', 'Kính Chu Lai / Việt Nhật', 'Trong suốt, mờ cát mờ hoặc dán decan logo', 'Kính Temper 12mm & Nẹp sập nhôm định hình', 'CAO CẤP', 'Kính dày 12mm', 'Nẹp sập nhôm / Keo kết cấu Apollo silicone', '2 năm hoàn thiện', 'Cách âm tốt giúp tập trung làm việc hiệu quả', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780134986/thanh-thinh-phat/proccxueggqyrp3yoek1.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(25, 'Vách kính trang trí nghệ thuật', 'vach-kinh-trang-tri-nghe-thuat', 'Vách kính trang trí ghép ô nghệ thuật phong cách châu Âu. Tạo điểm nhấn đắt giá cho sảnh lớn khách sạn, phòng khách biệt thự hoặc các căn hộ cao cấp.', '2.000.000 - 3.500.000 VNĐ/m²', 2, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135072/thanh-thinh-phat/c3mfrlenl062ksfatybw.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135072/thanh-thinh-phat/c3mfrlenl062ksfatybw.png', 0, '2026-05-30 16:53:08', 'VK-CL-006', 'Thành Thịnh Phát', 'Kính màu trà, kính gương bỉ, kính nhám', 'Kính tráng gương / Kính mài vát lá hẹ ghép thủ công', 'THỦ CÔNG MỸ THUẬT', 'Độ dày kính 5mm - 8mm', 'Băng keo chuyên dụng cường lực 3M & Silicone kết cấu', '5 năm chống bong tróc gương', 'Thẩm mỹ nghệ thuật trang trí đẳng cấp', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135072/thanh-thinh-phat/c3mfrlenl062ksfatybw.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(26, 'Lan can kính cầu thang tay vịn gỗ Căm Xe', 'lan-can-kinh-cau-thang-tay-vin-go-cam-xe', 'Lan can cầu thang kính cường lực tay vịn gỗ tự nhiên Căm Xe sang trọng. Kính Temper dày 10mm vững chãi, tạo điểm tựa chắc chắn và thẩm mỹ tinh tế cho các tầng nhà.', '1.600.000 - 2.800.000 VNĐ/m', 3, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135230/thanh-thinh-phat/zb5rfmn6kgeeweb3xwjh.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135230/thanh-thinh-phat/zb5rfmn6kgeeweb3xwjh.png', 0, '2026-05-30 16:53:08', 'LC-KK-004', 'Thành Thịnh Phát', 'Tay vịn màu gỗ tự nhiên đỏ sậm, kính trong suốt', 'Kính cường lực 10mm & Gỗ Căm Xe tròn/vuông', 'TIÊU CHUẨN', 'Kính dày 10mm, tay vịn gỗ đường kính 60mm', 'Trụ Inox 304 bắt hông / bắt mặt bậc, tai kẹp kính inox', '3 năm gỗ và phụ kiện', 'Kết cấu chịu lực va đập tuyệt đối an toàn', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135230/thanh-thinh-phat/zb5rfmn6kgeeweb3xwjh.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(27, 'Lan can kính âm sàn hiện đại tối giản', 'lan-can-kinh-am-san-hien-dai-toi-gian', 'Lan can kính chôn âm sàn cực kỳ tối giản. Không dùng trụ đỡ lộ thiên, kính cường lực 12mm được cố định chôn sâu trong sàn nhà mang lại vẻ đẹp tràn viền vô cực thời thượng.', '2.200.000 - 3.600.000 VNĐ/m', 3, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135322/thanh-thinh-phat/iwyqfavsm8edslx69cuj.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135322/thanh-thinh-phat/iwyqfavsm8edslx69cuj.png', 0, '2026-05-30 16:53:08', 'LC-KK-005', 'Hải Long Glass', 'Trong suốt hoàn toàn', 'Kính cường lực 12mm - 15mm hoặc kính dán an toàn', 'CAO CẤP', 'Kính dày 12mm trở lên', 'U Inox 304 định vị âm sàn, keo nở chịu lực chuyên dụng', '5 năm kết cấu chịu lực', 'View vô cực thông thoáng tối đa tầm nhìn', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135322/thanh-thinh-phat/iwyqfavsm8edslx69cuj.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(28, 'Lan can kính cường lực tay vịn inox 304', 'lan-can-kinh-cuong-luc-tay-vin-inox-304', 'Lan can kính cường lực ngoài trời sử dụng tay vịn inox 304 không rỉ sét. Thích hợp ban công nhà phố, biệt thự sát biển, chịu đựng được thời tiết nắng mưa khắc nghiệt cực tốt.', '1.400.000 - 2.500.000 VNĐ/m', 3, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135366/thanh-thinh-phat/zhkplq8afsd3qapwlt05.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135366/thanh-thinh-phat/zhkplq8afsd3qapwlt05.png', 0, '2026-05-30 16:53:08', 'LC-KK-006', 'Thành Thịnh Phát', 'Kim loại inox bóng / inox xước mờ', 'Kính Temper 10mm & Inox SUS 304 chống rỉ sét', 'TIÊU CHUẨN', 'Kính Temper dày 10mm, ống inox dày 1.2mm', 'Trụ lùn inox 304, pad đơn inox kẹp kính', '3 năm không han rỉ phụ kiện', 'Kết cấu kiên cố chắc chắn chống rung bão', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135366/thanh-thinh-phat/zhkplq8afsd3qapwlt05.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(29, 'Mái kính giếng trời tự động thông minh', 'mai-kinh-gieng-troi-tu-dong-thong-minh', 'Mái kính giếng trời trang bị động cơ tự động cảm biến mưa nắng thông minh. Khi trời mưa mái sẽ tự động đóng lại, kết cấu chịu lực an toàn tuyệt đối giúp lấy sáng tự nhiên cực tốt.', '4.500.000 - 7.500.000 VNĐ/m²', 4, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135407/thanh-thinh-phat/ln6yan9rtko9yukpgf40.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135407/thanh-thinh-phat/ln6yan9rtko9yukpgf40.png', 1, '2026-05-30 16:53:08', 'MK-CL-004', 'Động cơ Somfy Pháp / Tuya Smart', 'Khung xám ghi hoặc đen, kính phản quang chống nóng', 'Kính dán an toàn cường lực 11.52mm & Hệ khung thép I sơn chống rỉ', 'THÔNG MINH CAO CẤP', 'Kính dày 11.52mm (2 lớp dán)', 'Motor kéo tự động, cảm biến nước mưa thông minh', '5 năm khung, 2 năm động cơ và cảm biến', 'Cách âm chống va đập, lấy sáng và lưu thông khí tốt', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135407/thanh-thinh-phat/ln6yan9rtko9yukpgf40.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(30, 'Mái kính nghệ thuật tân cổ điển sang trọng', 'mai-kinh-nghe-thuat-tan-co-dien', 'Mái kính kết hợp khung sắt mỹ thuật uốn lượn phong cách tân cổ điển quý phái. Đem lại điểm nhấn đẳng cấp cho sảnh đón biệt thự lớn, lâu đài hoặc nhà hàng tiệc cưới.', '3.500.000 - 6.000.000 VNĐ/m²', 4, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Mai+Kinh+Nghe+Thuat', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Mai+Kinh+Nghe+Thuat', 0, '2026-05-30 16:53:08', 'MK-CL-005', 'Thành Thịnh Phát', 'Khung sắt nghệ thuật sơn tĩnh điện đen kết hợp nhũ vàng', 'Kính cường lực 12mm & Hệ khung sắt nghệ thuật dày dặn uốn hoa văn', 'CỔ ĐIỂN MỸ THUẬT', 'Kính dày 12mm phôi siêu trong hoặc kính mờ', 'Phụ kiện liên kết, bát bắt tường inox đúc hoa văn', '5 năm chất lượng hệ khung sắt sơn tĩnh điện', 'Che nắng mưa và trang trí kiến trúc hoàng gia', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Mai+Kinh+Nghe+Thuat\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=MAI+KINH+NGHE+THUAT+TAN+CO+DIEN+Detail+1\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=MAI+KINH+NGHE+THUAT+TAN+CO+DIEN+Detail+2\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(31, 'Mái kính cường lực khung xương inox', 'mai-kinh-cuong-luc-khung-inox', 'Mái che kính cường lực sử dụng khung kết cấu hoàn toàn bằng Inox 304 hộp bóng hoặc xước mờ. Bền bỉ tuyệt đối với thời gian, không lo hoen rỉ hay bong tróc sơn, kiểu dáng sang trọng.', '2.800.000 - 4.500.000 VNĐ/m²', 4, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Mai+Kinh+Khung+Inox', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Mai+Kinh+Khung+Inox', 0, '2026-05-30 16:53:08', 'MK-CL-006', 'Thành Thịnh Phát', 'Kim loại inox bóng sáng loáng', 'Kính Temper 10mm - 12mm & Hệ khung Inox SUS 304 hộp chịu lực', 'TIÊU CHUẨN', 'Kính dày 10mm, thanh Inox hộp dày 1.5mm trở lên', 'Trụ Spider đỡ kính inox 304, vít inox đặc chủng', '5 năm toàn diện', 'Lấy sáng tự nhiên, hiện đại không bị xuống cấp theo thời gian', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Mai+Kinh+Khung+Inox\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=MAI+KINH+CUONG+LUC+KHUNG+INOX+Detail+1\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=MAI+KINH+CUONG+LUC+KHUNG+INOX+Detail+2\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(32, 'Cửa cuốn khe thoáng Austdoor Supera', 'cua-cuon-khe-thoang-austdoor-supera', 'Dòng cửa cuốn nan nhôm khe thoáng thế hệ mới Supera của tập đoàn Austdoor. Vận hành siêu êm nhờ gioăng giảm chấn 2 chiều, tích hợp công nghệ đảo chiều khi gặp chướng ngại vật.', '1.800.000 - 3.200.000 VNĐ/m²', 5, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Cuon+Supera', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Cua+Cuon+Supera', 0, '2026-05-30 16:53:08', 'CC-AD-004', 'Austdoor chính hãng', 'Ghi sáng (#05), Cafe cháy (#07)', 'Hợp kim nhôm tiêu chuẩn AL 6063 T5 sơn tĩnh điện Tiger', 'THẾ HỆ MỚI', 'Nan nhôm dày 1.1mm - 1.3mm', 'Mô tơ AH hoặc AK đồng bộ, bình lưu điện Austdoor', '5 năm mô tơ, 2 năm nan cửa', 'Vận hành êm ái cách âm siêu êm giảm chấn', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Cuon+Supera\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=CUA+CUON+KHE+THOANG+AUSTDOOR+SUPERA+Detail+1\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=CUA+CUON+KHE+THOANG+AUSTDOOR+SUPERA+Detail+2\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(33, 'Cửa cuốn tấm liền Austdoor Series 1', 'cua-cuon-tam-lien-austdoor-series-1', 'Cửa cuốn tấm liền bằng thép hợp kim Colorbond công nghệ Úc siêu bền. Đóng mở cực kỳ nhanh chóng và êm ái bằng tay nhờ lò xo trợ lực hoặc gắn thêm motor tự động thông minh.', '1.400.000 - 2.500.000 VNĐ/m²', 5, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Cuon+Series+1', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Cua+Cuon+Series+1', 0, '2026-05-30 16:53:08', 'CC-AD-005', 'Austdoor chính hãng', 'Vàng kem (#02), Xanh ngọc (#04)', 'Thép hợp kim Colorbond của hãng BlueScope Steel Úc', 'TẤM LIỀN SIÊU BỀN', 'Độ dày thép tấm cửa 0.53mm', 'Lò xo trợ lực thép C75 của Úc, động cơ tấm liền ARG.P', '2 năm', 'Dây polyguide chạy dọc thân cửa giúp triệt tiêu tiếng ồn đến 95%', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Cuon+Series+1\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=CUA+CUON+TAM+LIEN+AUSTDOOR+SERIES+1+Detail+1\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=CUA+CUON+TAM+LIEN+AUSTDOOR+SERIES+1+Detail+2\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(34, 'Cửa cuốn chống cháy chuyên dụng', 'cua-cuon-chong-chay-chuyen-dung', 'Cửa cuốn chống cháy đạt tiêu chuẩn kiểm định PCCC. Thân cửa bằng thép siêu dày có phủ sơn nở nhiệt, tự động đóng kín ngăn lửa lây lan khi xảy ra sự cố cháy nổ tại kho xưởng.', '3.000.000 - 5.000.000 VNĐ/m²', 5, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Cuon+Chong+Chay', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Cua+Cuon+Chong+Chay', 0, '2026-05-30 16:53:08', 'CC-AD-006', 'Thành Thịnh Phát', 'Ghi tối sơn chịu nhiệt đặc chủng', 'Thép tấm chịu lực siêu dày kết hợp lớp cách nhiệt sợi gốm chống cháy', 'CHỐNG CHÁY KIỂM ĐỊNH', 'Tấm thép thân cửa dày 1.2mm - 1.5mm', 'Mô tơ xích chống cháy, tủ điều khiển cảm biến báo khói báo nhiệt', '3 năm', 'Chống cháy ngăn khói lửa độc hại tối đa lên đến 120-180 phút', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cua+Cuon+Chong+Chay\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=CUA+CUON+CHONG+CHAY+CHUYEN+DUNG+Detail+1\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=CUA+CUON+CHONG+CHAY+CHUYEN+DUNG+Detail+2\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(35, 'Vách tắm kính 135 độ cabin vát góc', 'vach-tam-kinh-135-do-cabin-vat-goc', 'Vách tắm kính 135 độ sử dụng phụ kiện inox định hình góc chéo vát 135 độ độc đáo. Giải pháp phân chia cabin tắm khô ướt lý tưởng cho phòng tắm rộng rãi hiện đại.', '2.800.000 - 4.200.000 VNĐ/bộ', 6, 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135518/thanh-thinh-phat/as7fakoxgk4qqhj2sbw7.png', 'https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135518/thanh-thinh-phat/as7fakoxgk4qqhj2sbw7.png', 1, '2026-05-30 16:53:08', 'PT-PT-004', 'VVP Thái Lan / Hiwin', 'Phụ kiện màu inox bóng / vàng gương / đen mờ', 'Kính cường lực Temper 10mm & Inox SUS 304 chuẩn', 'TIÊU CHUẨN', 'Kính dày 10mm', 'Bản lề 135 độ, giằng đỉnh inox, định vị sàn, gioăng chắn nước', '2 năm phụ kiện không rỉ sét', 'Cabin kín ngăn tuyệt đối nước bắn ra sàn vệ sinh sạch sẽ', 'Còn hàng', '[\"https://res.cloudinary.com/dg2jih9x0/image/upload/v1780135518/thanh-thinh-phat/as7fakoxgk4qqhj2sbw7.png\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\r\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\r\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\r\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\r\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\r\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\r\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\r\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(36, 'Vách tắm kính 180 độ cabin thẳng hàng', 'vach-tam-kinh-180-do', 'Vách tắm kính cabin thẳng 180 độ ngăn một phần không gian tắm. Sử dụng bản lề liên kết kính-kính mở hai chiều thẳng góc tiện lợi, phù hợp phòng tắm dạng hộp hẹp.', '2.600.000 - 3.800.000 VNĐ/bộ', 6, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Tam+180+Do', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Vach+Tam+180+Do', 0, '2026-05-30 16:53:08', 'PT-PT-005', 'Hafele Đức / VVP', 'Inox xước mờ sang trọng', 'Kính cường lực Hải Long 10mm & Phụ kiện inox đúc', 'CAO CẤP', 'Kính cường lực dày 10mm', 'Bản lề kính-kính 180 độ, pad liên kết tường, giằng cố định', '3 năm phụ kiện chính hãng', 'Giữ ấm trong cabin tắm cực tốt vào mùa đông, kín khít', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Tam+180+Do\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=VACH+TAM+KINH+180+DO+Detail+1\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=VACH+TAM+KINH+180+DO+Detail+2\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(37, 'Vách tắm kính cửa trượt treo lùa inox', 'vach-tam-kinh-cua-truot-treo-lua', 'Cabin tắm kính mở trượt lùa treo inox 10x30 hiện đại. Thiết kế cánh trượt trên ray lùa treo phía trên giúp đóng mở êm ái, tối ưu không gian cho các phòng tắm diện tích vừa và nhỏ.', '3.200.000 - 5.000.000 VNĐ/bộ', 6, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Tam+Cua+Truot', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Vach+Tam+Cua+Truot', 0, '2026-05-30 16:53:08', 'PT-PT-006', 'Hiwin chính hãng', 'Inox bóng gương', 'Kính cường lực Temper 10mm & Phụ kiện bánh xe ray lùa inox hộp', 'TIÊU CHUẨN', 'Kính Temper dày 10mm', 'Bộ ray trượt lùa inox 10x30, bánh xe trượt, dẫn hướng sàn', '2 năm', 'Tiết kiệm không gian mở cửa cabin, vận hành êm nhẹ', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Vach+Tam+Cua+Truot\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=VACH+TAM+KINH+CUA+TRUOT+TREO+LUA+Detail+1\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=VACH+TAM+KINH+CUA+TRUOT+TREO+LUA+Detail+2\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.'),
(38, 'Phòng tắm kính mờ cát cao cấp riêng tư', 'phong-tam-kinh-mo-cat-cao-cap', 'Cabin tắm vách kính được phun cát tạo độ mờ nhám mịn hoặc dán phim mờ nghệ thuật. Giải pháp mang lại không gian thư giãn sang trọng và sự riêng tư tối đa cho người sử dụng.', '3.500.000 - 5.500.000 VNĐ/bộ', 6, 'https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cabin+Tam+Kinh+Mo', 'https://placehold.co/400x300/1B2A4A/FFFFFF?text=Cabin+Tam+Kinh+Mo', 0, '2026-05-30 16:53:08', 'PT-PT-007', 'Hải Long Glass', 'Trắng mờ nhám cát mịn nghệ thuật', 'Kính cường lực phun cát mờ 10mm & Phụ kiện Inox mạ vàng quý phái', 'CAO CẤP SANG TRỌNG', 'Kính Temper mờ dày 10mm', 'Bản lề cabin tắm mạ vàng, tay nắm vắt khăn mạ vàng đồng bộ', '3 năm', 'Ngăn nước tối đa, che chắn tầm nhìn tạo sự kín đáo riêng tư', 'Còn hàng', '[\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=Cabin+Tam+Kinh+Mo\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=PHONG+TAM+KINH+MO+CAT+CAO+CAP+Detail+1\",\"https://placehold.co/800x600/1B2A4A/FFFFFF?text=PHONG+TAM+KINH+MO+CAT+CAO+CAP+Detail+2\"]', 'Thiết kế hiện đại, tinh giản theo xu hướng kiến trúc mới nhất.\nKhung liên kết vững chắc, chịu áp lực gió lớn và chống ngập úng cực tốt.\nKeo silicone liên kết chống thấm nước tuyệt đối, bảo vệ tường nhà.\nBề mặt sơn phủ tĩnh điện cao cấp, không phai màu hay trầy xước.', 'Khảo sát và Đo đạc: Đội ngũ thợ kỹ thuật đến trực tiếp công trình khảo sát hiện trạng và đo đạc kích thước thực tế chuẩn xác từng milimet.\nTư vấn và Chốt bản vẽ: Tư vấn phương án thiết kế tối ưu, chốt chủng loại vật liệu (nhôm, kính, phụ kiện) và báo giá minh bạch.\nGia công tại Xưởng: Sản phẩm được gia công, cắt ghép trên dây chuyền máy móc hiện đại tại nhà xưởng Thành Thịnh Phát.\nLắp đặt & Nghiệm thu: Vận chuyển an toàn, tiến hành căn chỉnh, lắp đặt chắc chắn tại công trình, bắn keo silicone liên kết chống thấm nước tuyệt đối.\nBàn giao & Bảo hành: Vệ sinh sạch sẽ, vận hành thử êm ái, bàn giao phiếu bảo hành chính hãng từ 2 đến 5 năm cho khách hàng.');
